mapper.select:
SELECT ro.*, u.real_name AS student_name, b.name AS building_name, r.room_no AS room_no, rt.type_name AS repair_type_name FROM repair_order ro LEFT JOIN sys_user u ON ro.student_id = u.id LEFT JOIN dorm_building b ON ro.building_id = b.id LEFT JOIN dorm_room r ON ro.room_id = r.id LEFT JOIN repair_type rt ON ro.repair_type_id = rt.id
AND ro.student_id = #{studentId}
AND ro.repair_user_id = #{repairUserId}
AND ro.status IN
#{item}
AND ro.status = #{status}
AND ro.repair_type_id = #{repairTypeId}
AND (u.real_name LIKE CONCAT('%', #{keyword}, '%') OR ro.description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY ro.create_time DESC
